import { readFileSync } from 'node:fs';
const rendering=readFileSync('apps/liora/src/tui/constant/rendering.ts','utf8');
const appearance=readFileSync('apps/liora/src/tui/utils/appearance-effects.ts','utf8');
const activity=readFileSync('apps/liora/src/tui/components/panes/activity-pane.ts','utf8');
const welcome=readFileSync('apps/liora/src/tui/components/chrome/welcome.ts','utf8');
const strategy=readFileSync('packages/agent-core/src/agent/compaction/strategy.ts','utf8');
const swarm=readFileSync('apps/liora/src/tui/components/messages/agent-swarm-progress.ts','utf8');
const fails=[];
if (!rendering.includes('THINKING_PREVIEW_LINES = 4')) fails.push('think4');
if (!rendering.includes('COMMAND_PREVIEW_LINES = 4')) fails.push('cmd4');
if (!rendering.includes('RESULT_PREVIEW_LINES = 3')) fails.push('res3');
if (!appearance.includes('PREMIUM_AMBIENT_RENDER_TICK_MS = 33')) fails.push('ambient33');
if (activity.includes('railA') || activity.includes('railB')) fails.push('activity-dual');
if (welcome.includes('welcome-top') && welcome.includes('welcome-bottom')) fails.push('welcome-dual');
if (!strategy.includes('DEFAULT_COMPACTION_TRIGGER_RATIO = 0.80')) fails.push('soft80');
if (!strategy.includes('assertCompactionLadderSafety')) fails.push('safety');
if (!swarm.includes('MAX_LATEST_MODEL_CHARS = 480')) fails.push('swarm-ring-480');
if (fails.length){console.error(fails.join(',')); process.exit(1);} console.log('tui-ux-contract-ok');
